 48→/** Simple hash to avoid storing raw API keys on disk */
 49→function hashKey(key: string): string {
 50→  let h = 0;
 51→  for (let i = 0; i < key.length; i++) {
 52→    h = ((h << 5) - h + key.charCodeAt(i)) | 0;
 53→  }
 54→  return h.toString(36);
