import { preprocessGraphLinks, parseGraphLinkUrl } from '../lib/graphLinks'
import FigmaEmbed from '../components/FigmaEmbed'
import { REACTION_EMOJI, REACTION_ORDER } from '../lib/reactionUtils'
import MentionTextarea from '../components/MentionTextarea'

const FIGMA_URL_RE = /(^|[\s\n])(https:\/\/(?:www\.)?figma\.com\/(?:file|design|proto)\/[^\s\n)]+)/g

function preprocessFigmaUrls(content: string): string {
  return content.replace(FIGMA_URL_RE, (_, prefix, url) => `${prefix}[${url}](${url})`)
}

function ReactionBar({
  reactions,
  onToggle,
}: {
  reactions?: GitHubReaction[]
  onToggle?: (reaction: string) => void
}) {
  const [showPicker, setShowPicker] = useState(false)
  const pickerRef = useRef<HTMLDivElement>(null)
  const byType = Object.fromEntries((reactions ?? []).map(r => [r.reaction, r]))
  const nonZero = REACTION_ORDER.filter(r => byType[r]?.count > 0)

  useEffect(() => {
    if (!showPicker) return
    const handler = (e: MouseEvent) => {
      if (pickerRef.current && !pickerRef.current.contains(e.target as Node)) {
        setShowPicker(false)
      }
    }
    document.addEventListener('mousedown', handler)
    return () => document.removeEventListener('mousedown', handler)
  }, [showPicker])

  if (!nonZero.length && !onToggle) return null
  return (
    <div className="flex flex-wrap items-center gap-1.5 mt-2">
      {nonZero.map(r => (
        <button
          key={r}
          type="button"
          onClick={() => onToggle?.(r)}
          className={`inline-flex items-center gap-1 text-xs border rounded-full px-2 py-0.5 transition-colors
            ${byType[r].user_reacted
              ? 'bg-primary-500/20 border-primary-500/50 text-primary-300'
              : 'bg-dark-bg-secondary border-dark-border-subtle text-dark-text-secondary hover:border-dark-border-medium'}
            ${onToggle ? 'cursor-pointer' : 'cursor-default'}`}
        >
          {REACTION_EMOJI[r]} {byType[r].count}
        </button>
      ))}
      {onToggle && (
        <div className="relative" ref={pickerRef}>
          <button
            type="button"
            onClick={() => setShowPicker(p => !p)}
            className="inline-flex items-center justify-center h-5 px-1.5 text-xs border border-dashed border-dark-border-subtle rounded-full text-dark-text-tertiary hover:text-dark-text-secondary hover:border-dark-border-medium transition-colors"
            title="Add reaction"
          >
            😊 +
          </button>
          {showPicker && (
            <div className="absolute bottom-full left-0 mb-1 bg-dark-bg-secondary border border-dark-border-subtle rounded-lg shadow-xl p-1.5 flex gap-0.5 z-50">
              {REACTION_ORDER.map(r => (
                <button
                  key={r}
                  type="button"
                  onClick={() => { onToggle(r); setShowPicker(false) }}
                  title={r}
                  className={`text-base p-1 rounded hover:bg-dark-bg-tertiary transition-colors ${byType[r]?.user_reacted ? 'bg-primary-500/20' : ''}`}
                >
                  {REACTION_EMOJI[r]}
                </button>
              ))}
            </div>
          )}
        </div>
      )}
    </div>
  )
}

interface TaskDetailProps {
  isModal?: boolean
  onClose?: () => void
}

export default function TaskDetail({ isModal, onClose }: TaskDetailProps) {
  const { projectId, taskNumber } = useParams()
  const navigate = useNavigate()
  const [task, setTask] = useState<Task | null>(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [saving, setSaving] = useState(false)

  // Inline editing
  const [editingField, setEditingField] = useState<string | null>(null)
  const [editValue, setEditValue] = useState('')
  const titleRef = useRef<HTMLInputElement>(null)
  const descRef = useRef<HTMLTextAreaElement>(null)
  const commentRef = useRef<HTMLTextAreaElement>(null)

  // Reference data
  const [sprints, setSprints] = useState<Sprint[]>([])
  const [swimLanes, setSwimLanes] = useState<SwimLane[]>([])
  const [members, setMembers] = useState<ProjectMember[]>([])
  const [projectTags, setProjectTags] = useState<Tag[]>([])

  // Attachments
  const [attachments, setAttachments] = useState<Attachment[]>([])
  const [uploading, setUploading] = useState(false)
  const [editingAltId, setEditingAltId] = useState<number | null>(null)
  const [editingAltValue, setEditingAltValue] = useState('')
  const [pendingFile, setPendingFile] = useState<File | null>(null)
  const fileInputRef = useRef<HTMLInputElement>(null)

  // Comments
  const [comments, setComments] = useState<TaskComment[]>([])
  const [newComment, setNewComment] = useState('')
  const [postingComment, setPostingComment] = useState(false)

  // Image picker
  const [imagePickerTarget, setImagePickerTarget] = useState<'description' | 'comment' | null>(null)

  // Confirm modal
  const [confirmAction, setConfirmAction] = useState<{ message: string; onConfirm: () => void } | null>(null)

  // GitHub push
  const [pushingToGitHub, setPushingToGitHub] = useState(false)
  const [githubPushResult, setGithubPushResult] = useState<GitHubPushTaskResponse | null>(null)
  const [githubRepo, setGithubRepo] = useState<{ github_owner: string; github_repo_name: string } | null>(null)

  // Reaction toggle with optimistic updates
  const handleToggleReaction = useCallback(async (reaction: string, commentId?: number) => {
    if (!task) return
    const taskIdNum = Number(task.id)

    // Optimistic update
    const applyOptimistic = (reactions: GitHubReaction[] | undefined, toggling: boolean): GitHubReaction[] => {
      const list = reactions ? [...reactions] : []
      const idx = list.findIndex(r => r.reaction === reaction)
      if (toggling) {
        // Adding
        if (idx >= 0) {
          list[idx] = { ...list[idx], count: list[idx].count + 1, user_reacted: true }
        } else {
          list.push({ reaction, count: 1, user_reacted: true })
        }
      } else {
        // Removing
        if (idx >= 0) {
          const newCount = Math.max(0, list[idx].count - 1)
          list[idx] = { ...list[idx], count: newCount, user_reacted: false }
        }
      }
      return list
    }

    const wasReacted = commentId
      ? comments.find(c => c.id === commentId)?.github_reactions?.find(r => r.reaction === reaction)?.user_reacted ?? false
      : task.github_reactions?.find(r => r.reaction === reaction)?.user_reacted ?? false

    if (commentId) {
      setComments(prev => prev.map(c =>
        c.id === commentId
          ? { ...c, github_reactions: applyOptimistic(c.github_reactions, !wasReacted) }
          : c
      ))
    } else {
      setTask(prev => prev ? { ...prev, github_reactions: applyOptimistic(prev.github_reactions, !wasReacted) } : prev)
    }

    try {
      const result = await apiClient.toggleReaction(taskIdNum, reaction, commentId)
      // Apply authoritative result
      if (commentId) {
        setComments(prev => prev.map(c => {
          if (c.id !== commentId) return c
          const list = c.github_reactions ? [...c.github_reactions] : []
          const idx = list.findIndex(r => r.reaction === reaction)
          if (idx >= 0) {
            list[idx] = { reaction, count: result.count, user_reacted: result.user_reacted }
          } else {
            list.push({ reaction, count: result.count, user_reacted: result.user_reacted })
          }
          return { ...c, github_reactions: list }
        }))
      } else {
        setTask(prev => {
          if (!prev) return prev
          const list = prev.github_reactions ? [...prev.github_reactions] : []
          const idx = list.findIndex(r => r.reaction === reaction)
          if (idx >= 0) {
            list[idx] = { reaction, count: result.count, user_reacted: result.user_reacted }
          } else {
            list.push({ reaction, count: result.count, user_reacted: result.user_reacted })
          }
          return { ...prev, github_reactions: list }
        })
      }
    } catch {
      // Revert optimistic update
      if (commentId) {
        setComments(prev => prev.map(c =>
          c.id === commentId
            ? { ...c, github_reactions: applyOptimistic(c.github_reactions, wasReacted) }
            : c
        ))
      } else {
        setTask(prev => prev ? { ...prev, github_reactions: applyOptimistic(prev.github_reactions, wasReacted) } : prev)
      }
    }
  }, [task, comments])

  useEffect(() => {
    loadTask()
    loadSprints()
    loadSwimLanes()
    loadMembers()
    loadProjectTags()
    if (projectId) {
      apiClient.getProjectGitHub(Number(projectId))
        .then(s => setGithubRepo({ github_owner: s.github_owner, github_repo_name: s.github_repo_name }))
        .catch(() => {})
    }
  }, [projectId, taskNumber]) // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    if (task?.id) {
      loadComments(task.id)
      loadAttachments(task.id)
    }
  }, [task?.id]) // eslint-disable-line react-hooks/exhaustive-deps

  useEffect(() => {
    if (editingField === 'title') titleRef.current?.focus()
    if (editingField === 'description') {
      const el = descRef.current
      if (el) {
        el.focus()
        el.setSelectionRange(el.value.length, el.value.length)
      }
    }
  }, [editingField])

  const handlePushToGitHub = async () => {
    if (!task?.id) return
    setPushingToGitHub(true)
    try {
      const result = await apiClient.githubPushTask(task.id)
      setGithubPushResult(result)
      setTask(prev => prev ? { ...prev, github_issue_number: result.issue_number } : prev)
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to push to GitHub')
    } finally {
      setPushingToGitHub(false)
    }
  }

  const loadTask = async () => {
    try {
      setLoading(true)
      const found = await apiClient.getTaskByNumber(Number(projectId), Number(taskNumber))
      setTask(found)
      if (found.github_issue_number) {
        setGithubPushResult({ issue_number: found.github_issue_number, html_url: '' })
      }
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to load task')
    } finally {
      setLoading(false)
    }
  }

  const loadSprints = async () => {
    try { setSprints(await apiClient.getSprints(Number(projectId))) } catch { /* ignore */ }
  }

  const loadSwimLanes = async () => {
    try {
      const lanes = await apiClient.getSwimLanes(Number(projectId))
      setSwimLanes(lanes.sort((a, b) => a.position - b.position))
    } catch { /* ignore */ }
  }

  const loadComments = async (id?: number) => {
    const taskId = id ?? task?.id
    if (!taskId) return
    try { setComments(await apiClient.getTaskComments(taskId)) } catch { /* ignore */ }
  }

  const loadMembers = async () => {
    try { setMembers(await apiClient.getProjectMembers(Number(projectId))) } catch { /* ignore */ }
  }

  const loadProjectTags = async () => {
    try { setProjectTags(await apiClient.getTags(Number(projectId))) } catch { /* ignore */ }
  }

  const saveTagIds = async (tagIds: number[]) => {
    if (!task?.id) return
    try {
      await apiClient.updateTask(task.id, { tag_ids: tagIds })
      await loadTask()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to update tags')
    }
  }

  const saveAssigneeIds = async (userIds: number[]) => {
    if (!task?.id) return
    try {
      await apiClient.updateTask(task.id, { assignee_ids: userIds })
      await loadTask()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to update assignees')
    }
  }

  const loadAttachments = async (id?: number) => {
    const taskId = id ?? task?.id
    if (!taskId) return
    try { setAttachments(await apiClient.getTaskAttachments(taskId)) } catch { /* ignore */ }
  }

  const handleFileUpload = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0]
    if (!file) return

    const allowedTypes = ['image/', 'video/', 'application/pdf']
    if (!allowedTypes.some(t => file.type.startsWith(t))) {
      setError('Only images, videos, and PDFs are allowed')
      e.target.value = ''
      return
    }

    setPendingFile(file)
    e.target.value = ''
  }

  const handleConfirmUpload = async (file: File, altText: string) => {
    try {
      setUploading(true)
      const sig = await apiClient.getUploadSignature({ taskId: task!.id! })

      const formData = new FormData()
      formData.append('file', file)
      formData.append('api_key', sig.api_key)
      formData.append('timestamp', String(sig.timestamp))
      formData.append('signature', sig.signature)
      formData.append('folder', sig.folder)
      formData.append('public_id', sig.public_id)

      const uploadRes = await fetch(
        `https://api.cloudinary.com/v1_1/${sig.cloud_name}/auto/upload`,
        { method: 'POST', body: formData }
      )

      if (!uploadRes.ok) throw new Error('Upload to Cloudinary failed')
      const uploadData = await uploadRes.json()

      let fileType = 'image'
      if (file.type.startsWith('video/')) fileType = 'video'
      else if (file.type === 'application/pdf') fileType = 'pdf'

      await apiClient.createTaskAttachment(task!.id!, {
        filename: file.name,
        alt_name: altText,
        file_type: fileType,
        content_type: file.type,
        file_size: file.size,
        cloudinary_url: uploadData.secure_url,
        cloudinary_public_id: uploadData.public_id,
      })

      await loadAttachments()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to upload file')
    } finally {
      setUploading(false)
      setPendingFile(null)
    }
  }

  const handleDeleteAttachment = (attachmentId: number) => {
    setConfirmAction({
      message: 'Are you sure you want to delete this attachment? This cannot be undone.',
      onConfirm: async () => {
        try {
          await apiClient.deleteTaskAttachment(task!.id!, attachmentId)
          await loadAttachments()
        } catch (err: unknown) {
          setError(err instanceof Error ? err.message : 'Failed to delete attachment')
        }
        setConfirmAction(null)
      },
    })
  }

  const handleSaveAltName = async (attachmentId: number) => {
    try {
      await apiClient.updateAttachment(attachmentId, { alt_name: editingAltValue })
      setEditingAltId(null)
      await loadAttachments()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to update alt name')
    }
  }

  const insertImageMarkdown = useCallback((alt: string, url: string) => {
    const markdown = `![${alt}](${url})`

    if (imagePickerTarget === 'description' && descRef.current) {
      const textarea = descRef.current
      const start = textarea.selectionStart
      const end = textarea.selectionEnd
      const text = editValue
      const newText = text.substring(0, start) + markdown + text.substring(end)
      setEditValue(newText)
      setTimeout(() => {
        textarea.focus()
        const cursorPos = start + markdown.length
        textarea.setSelectionRange(cursorPos, cursorPos)
      }, 0)
    } else if (imagePickerTarget === 'comment' && commentRef.current) {
      const textarea = commentRef.current
      const start = textarea.selectionStart
      const end = textarea.selectionEnd
      const newText = newComment.substring(0, start) + markdown + newComment.substring(end)
      setNewComment(newText)
      setTimeout(() => {
        textarea.focus()
        const cursorPos = start + markdown.length
        textarea.setSelectionRange(cursorPos, cursorPos)
      }, 0)
    }

    setImagePickerTarget(null)
  }, [imagePickerTarget, editValue, newComment])

  const saveField = async (field: string, value: string) => {
    if (!task) return
    try {
      setSaving(true)
      const update: Partial<UpdateTaskRequest> = {}

      switch (field) {
        case 'title':
          if (!value?.trim()) return
          update.title = value.trim()
          break
        case 'description':
          update.description = value?.trim() || ''
          break
        case 'swim_lane_id': {
          // Backend auto-syncs status from swim lane's status_category
          update.swim_lane_id = Number(value)
          break
        }
        case 'priority':
          update.priority = value as UpdateTaskRequest['priority']
          break
        case 'sprint_id':
          update.sprint_id = value ? parseInt(value) : null
          break
        case 'assignee_id':
          update.assignee_id = value ? parseInt(value) : null
          break
        case 'start_date':
          update.start_date = value || null
          break
        case 'due_date':
          update.due_date = value || null
          break
        case 'estimated_hours':
          update.estimated_hours = value ? parseFloat(value) : 0
          break
        case 'actual_hours':
          update.actual_hours = value ? parseFloat(value) : 0
          break
      }

      await apiClient.updateTask(task.id!, update)
      await loadTask()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to update')
    } finally {
      setSaving(false)
      setEditingField(null)
    }
  }

  const startEdit = (field: string, currentValue: string) => {
    setEditingField(field)
    setEditValue(currentValue)
  }

  const cancelEdit = () => {
    setEditingField(null)
    setEditValue('')
  }

  const handleKeyDown = (e: React.KeyboardEvent, field: string) => {
    if (e.key === 'Enter' && !e.shiftKey) {
      e.preventDefault()
      saveField(field, editValue)
    } else if (e.key === 'Escape') {
      cancelEdit()
    }
  }

  const handlePostComment = async () => {
    if (!newComment.trim()) return
    try {
      setPostingComment(true)
      await apiClient.createTaskComment(task!.id!, newComment.trim())
      setNewComment('')
      await loadComments()
    } catch (err: unknown) {
      setError(err instanceof Error ? err.message : 'Failed to post comment')
    } finally {
      setPostingComment(false)
    }
  }

  const handleDelete = () => {
    if (!task) return
    setConfirmAction({
      message: 'Are you sure you want to delete this task? This action cannot be undone.',
      onConfirm: async () => {
        try {
          await apiClient.deleteTask(task.id!)
          setConfirmAction(null)
          handleClose()
        } catch (err: unknown) {
          setError(err instanceof Error ? err.message : 'Failed to delete task')
          setConfirmAction(null)
        }
      },
    })
  }

  const handleClose = () => {
    if (onClose) onClose()
    else navigate(`/app/projects/${projectId}`)
  }

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'urgent': return 'bg-danger-500/10 text-danger-400 border-danger-500/30'
      case 'high': return 'bg-warning-500/10 text-warning-400 border-warning-500/30'
      case 'medium': return 'bg-yellow-500/10 text-yellow-400 border-yellow-500/30'
      case 'low': return 'bg-success-500/10 text-success-400 border-success-500/30'
      default: return 'bg-dark-bg-tertiary text-dark-text-tertiary border-dark-border-subtle'
    }
  }

  const getStatusColor = (status: string) => {
    switch (status) {
      case 'done': return 'bg-success-500/10 text-success-400 border-success-500/30'
      case 'in_progress': return 'bg-primary-500/10 text-primary-400 border-primary-500/30'
      case 'todo': return 'bg-dark-bg-tertiary text-dark-text-tertiary border-dark-border-subtle'
      default: return 'bg-dark-bg-tertiary text-dark-text-tertiary border-dark-border-subtle'
    }
  }

  const getStatusLabel = (status: string) => {
    switch (status) {
      case 'done': return 'Done'
      case 'in_progress': return 'In Progress'
      case 'todo': return 'To Do'
      default: return status
    }
  }

  if (loading) {
    return (
      <div className={`${isModal ? 'p-8' : 'min-h-screen bg-dark-bg-primary'} flex items-center justify-center`}>
        <div className="text-dark-text-secondary">Loading task...</div>
      </div>
    )
  }

  if (error && !task) {
    return (
      <div className={`${isModal ? 'p-8' : 'min-h-screen bg-dark-bg-primary py-8'}`}>
        <div className={`${isModal ? '' : 'max-w-7xl mx-auto px-4 sm:px-6 lg:px-8'}`}>
          <div className="bg-dark-bg-secondary border border-dark-border-subtle rounded-lg p-8 text-center">
            <p className="text-danger-400 mb-4">{error}</p>
            <Button onClick={handleClose}>
              {isModal ? 'Close' : 'Back to Project'}
            </Button>
          </div>
        </div>
      </div>
    )
  }

  if (!task) return null

  const containerClass = isModal ? '' : 'min-h-screen bg-dark-bg-primary'
  const innerClass = isModal ? 'px-6' : 'max-w-7xl mx-auto px-4 sm:px-6 lg:px-8'

  return (
    <div className={containerClass}>
      {/* Header */}
      <div className="border-b border-dark-border-subtle bg-dark-bg-secondary sticky top-0 z-10">
        <div className={`${innerClass} py-4`}>
          <div className="flex items-center justify-between mb-3">
            <button
              onClick={handleClose}
              className="inline-flex items-center text-sm text-dark-text-secondary hover:text-dark-text-primary transition-colors"
            >
              {isModal ? (
                <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                  <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                </svg>
              ) : (
                <>
                  <svg className="w-4 h-4 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M10 19l-7-7m0 0l7-7m-7 7h18" />
                  </svg>
                  Back to project
                </>
              )}
            </button>
            <button
              onClick={handleDelete}
              className="p-2 text-danger-400 hover:text-danger-300 hover:bg-danger-500/20 rounded-lg transition-colors"
              title="Delete task"
            >
              <svg className="w-5 h-5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
              </svg>
            </button>
          </div>

          {/* Task number */}
          {task.task_number && (
            <span className="text-sm font-mono text-dark-text-tertiary mb-1">#{task.task_number}</span>
          )}

          {/* Title - inline editable */}
          {editingField === 'title' ? (
            <input
              ref={titleRef}
              type="text"
              value={editValue}
              onChange={(e) => setEditValue(e.target.value)}
              onBlur={() => saveField('title', editValue)}
              onKeyDown={(e) => handleKeyDown(e, 'title')}
              className="w-full text-2xl font-bold px-2 py-1 -ml-2 border border-dark-border-subtle bg-dark-bg-primary text-dark-text-primary rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none"
            />
          ) : (
            <h1
              onClick={() => startEdit('title', task.title || '')}
              className="text-2xl font-bold text-dark-text-primary cursor-text hover:bg-dark-bg-tertiary/50 px-2 py-1 -ml-2 rounded-lg transition-colors"
              title="Click to edit title"
            >
              {task.title}
            </h1>
          )}

          {/* Status badges */}
          <div className="flex flex-wrap gap-2 mt-2">
            {task.status && (
              <span className={`px-2.5 py-1 text-xs font-semibold rounded-full border ${getStatusColor(task.status)}`}>
                {getStatusLabel(task.status)}
              </span>
            )}
            {task.priority && (
              <span className={`px-2.5 py-1 text-xs font-semibold rounded-full border ${getPriorityColor(task.priority)}`}>
                {task.priority}
              </span>
            )}
            {task.tags && task.tags.length > 0 && task.tags.map((tag) => (
              <span
                key={tag.id}
                className="px-2.5 py-1 text-xs font-semibold rounded-full border border-dark-border-subtle"
                style={{ backgroundColor: tag.color + '20', color: tag.color }}
              >
                {tag.name}
              </span>
            ))}
            {saving && (
              <span className="px-2.5 py-1 text-xs text-dark-text-tertiary animate-pulse">
                Saving...
              </span>
            )}
          </div>
        </div>
      </div>

      {/* Main Content */}
      <div className={`${innerClass} py-6`}>
        <div className="flex flex-col md:flex-row gap-6">
          {/* Left Column - Description & Comments */}
          <div className="flex-1 min-w-0 space-y-6">
            {/* Description */}
            <div className="bg-dark-bg-secondary border border-dark-border-subtle rounded-lg p-6">
              <div className="flex items-center justify-between mb-3">
                <h2 className="text-sm font-semibold text-dark-text-primary">Description</h2>
                {editingField !== 'description' && (
                  <button
                    onClick={() => startEdit('description', task.description || '')}
                    className="p-1.5 text-dark-text-tertiary hover:text-dark-text-primary hover:bg-dark-bg-tertiary rounded-md transition-colors"
                    title="Edit description"
                  >
                    <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15.232 5.232l3.536 3.536m-2.036-5.036a2.5 2.5 0 113.536 3.536L6.5 21.036H3v-3.572L16.732 3.732z" />
                    </svg>
                  </button>
                )}
              </div>

              {editingField === 'description' ? (
                <div>
                  {/* Toolbar */}
                  <div className="flex items-center gap-1 mb-1">
                    <button
                      onClick={() => setImagePickerTarget('description')}
                      className="inline-flex items-center gap-1 px-2 py-1 text-xs text-dark-text-tertiary hover:text-primary-400 hover:bg-primary-500/10 rounded transition-colors"
                      title="Insert image"
                    >
                      <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                        <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                      </svg>
                      Insert image
                    </button>
                  </div>
                  <textarea
                    ref={descRef}
                    value={editValue}
                    onChange={(e) => setEditValue(e.target.value)}
                    rows={12}
                    className="w-full px-3 py-2 border border-dark-border-subtle bg-dark-bg-primary text-dark-text-primary rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none font-mono text-sm placeholder-dark-text-tertiary"
                    placeholder="Add a description in markdown format..."
                    onKeyDown={(e) => {
                      if (e.key === 'Escape') cancelEdit()
                      if (e.key === 'Enter' && (e.metaKey || e.ctrlKey)) {
                        e.preventDefault()
                        saveField('description', editValue)
                      }
                    }}
                  />
                  <div className="flex items-center gap-2 mt-2">
                    <Button size="sm" onClick={() => saveField('description', editValue)} disabled={saving}>
                      {saving ? 'Saving...' : 'Save'}
                    </Button>
                    <Button size="sm" variant="secondary" onClick={cancelEdit}>
                      Cancel
                    </Button>
                    <span className="text-xs text-dark-text-tertiary ml-auto">
                      Markdown supported &middot; {navigator.platform.includes('Mac') ? 'Cmd' : 'Ctrl'}+Enter to save
                    </span>
                  </div>
                </div>
              ) : task.description ? (
                <div className="prose prose-sm max-w-none prose-headings:text-dark-text-primary prose-p:text-dark-text-secondary prose-a:text-primary-400 prose-code:text-primary-400 prose-code:bg-primary-500/10 prose-code:px-1 prose-code:py-0.5 prose-code:rounded prose-pre:bg-dark-bg-primary prose-pre:border prose-pre:border-dark-border-subtle prose-strong:text-dark-text-primary prose-li:text-dark-text-secondary prose-img:rounded-lg prose-img:border prose-img:border-dark-border-subtle">
                  <ReactMarkdown
                    remarkPlugins={[remarkGfm, remarkEmoji]}
                    components={{
                      a: ({ href, children }) => {
                        if (href && /figma\.com\/(file|design|proto)\//.test(href)) {
                          return <FigmaEmbed url={href} size="m" />
                        }
                        const graphLink = href ? parseGraphLinkUrl(href) : null
                        if (graphLink) {
                          const label = String(children)
                          const handleClick = () => {
                            if (graphLink.type === 'wiki') {
                              navigate(`/app/projects/${projectId}?tab=wiki&page=${graphLink.id}`)
                            } else {
                              navigate(`/app/projects/${projectId}`)
                            }
                          }
                          return (
                            <button
                              onClick={handleClick}
                              className={`inline-flex items-center gap-1 px-2 py-0.5 rounded-full text-xs font-medium not-prose border transition-colors ${
                                graphLink.type === 'wiki'
                                  ? 'bg-blue-500/15 text-blue-400 border-blue-500/30 hover:bg-blue-500/25'
                                  : 'bg-orange-500/15 text-orange-400 border-orange-500/30 hover:bg-orange-500/25'
                              }`}
                            >
                              <span>{graphLink.type === 'wiki' ? '📄' : '✅'}</span>
                              {label}
                            </button>
                          )
                        }
                        return <a href={href}>{children}</a>
                      },
                    }}
                  >
                    {preprocessFigmaUrls(preprocessGraphLinks(task.description))}
                  </ReactMarkdown>
                  <ReactionBar reactions={task.github_reactions} onToggle={(r) => handleToggleReaction(r)} />
                </div>
              ) : (
                <p
                  className="text-sm text-dark-text-tertiary italic cursor-pointer hover:text-dark-text-secondary transition-colors"
                  onClick={() => startEdit('description', '')}
                >
                  Click to add a description...
                </p>
              )}
            </div>

            {/* Attachments Section */}
            <div className="bg-dark-bg-secondary border border-dark-border-subtle rounded-lg p-6">
              <div className="flex items-center justify-between mb-4">
                <h2 className="text-sm font-semibold text-dark-text-primary">
                  Attachments {attachments.length > 0 && `(${attachments.length})`}
                </h2>
                <label className={`inline-flex items-center gap-1.5 px-3 py-1.5 text-xs font-medium rounded-md cursor-pointer transition-colors ${
                  uploading
                    ? 'bg-dark-bg-tertiary text-dark-text-tertiary cursor-not-allowed'
                    : 'bg-primary-500/10 text-primary-400 hover:bg-primary-500/20'
                }`}>
                  <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 16a4 4 0 01-.88-7.903A5 5 0 1115.9 6L16 6a5 5 0 011 9.9M15 13l-3-3m0 0l-3 3m3-3v12" />
                  </svg>
                  {uploading ? 'Uploading...' : 'Upload'}
                  <input
                    ref={fileInputRef}
                    type="file"
                    className="hidden"
                    accept="image/*,video/*,.pdf"
                    onChange={handleFileUpload}
                    disabled={uploading}
                  />
                </label>
              </div>

              {attachments.length === 0 ? (
                <p className="text-sm text-dark-text-tertiary italic">No attachments</p>
              ) : (
                <div className="grid grid-cols-2 sm:grid-cols-3 gap-3">
                  {attachments.map((att: Attachment) => (
                    <div key={att.id} className="group relative border border-dark-border-subtle rounded-lg overflow-hidden bg-dark-bg-primary">
                      {att.file_type === 'image' ? (
                        <a href={att.cloudinary_url} target="_blank" rel="noopener noreferrer">
                          <img
                            src={att.cloudinary_url}
                            alt={att.alt_name || att.filename}
                            className="w-full h-24 object-cover"
                          />
                        </a>
                      ) : att.file_type === 'video' ? (
                        <a href={att.cloudinary_url} target="_blank" rel="noopener noreferrer" className="flex items-center justify-center h-24 bg-dark-bg-tertiary">
                          <svg className="w-8 h-8 text-dark-text-tertiary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M14.752 11.168l-3.197-2.132A1 1 0 0010 9.87v4.263a1 1 0 001.555.832l3.197-2.132a1 1 0 000-1.664z" />
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M21 12a9 9 0 11-18 0 9 9 0 0118 0z" />
                          </svg>
                        </a>
                      ) : (
                        <a href={att.cloudinary_url} target="_blank" rel="noopener noreferrer" className="flex items-center justify-center h-24 bg-dark-bg-tertiary">
                          <svg className="w-8 h-8 text-dark-text-tertiary" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                            <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M7 21h10a2 2 0 002-2V9.414a1 1 0 00-.293-.707l-5.414-5.414A1 1 0 0012.586 3H7a2 2 0 00-2 2v14a2 2 0 002 2z" />
                          </svg>
                        </a>
                      )}
                      <div className="p-2">
                        {editingAltId === att.id ? (
                          <input
                            type="text"
                            value={editingAltValue}
                            onChange={(e) => setEditingAltValue(e.target.value)}
                            onBlur={() => handleSaveAltName(att.id)}
                            onKeyDown={(e) => {
                              if (e.key === 'Enter') handleSaveAltName(att.id)
                              if (e.key === 'Escape') setEditingAltId(null)
                            }}
                            className="w-full text-xs bg-dark-bg-tertiary border border-dark-border-subtle text-dark-text-primary rounded px-1.5 py-0.5 outline-none focus:ring-1 focus:ring-primary-500"
                            autoFocus
                            placeholder="Alt name..."
                          />
                        ) : (
                          <p
                            className="text-xs text-dark-text-primary truncate cursor-pointer hover:text-primary-400 transition-colors"
                            title={`Click to edit alt name: ${att.alt_name || att.filename}`}
                            onClick={() => {
                              setEditingAltId(att.id)
                              setEditingAltValue(att.alt_name || '')
                            }}
                          >
                            {att.alt_name || att.filename}
                          </p>
                        )}
                        <p className="text-[10px] text-dark-text-tertiary">
                          {(att.file_size / 1024 / 1024).toFixed(1)} MB
                        </p>
                      </div>
                      <button
                        onClick={() => handleDeleteAttachment(att.id)}
                        className="absolute top-1 right-1 p-1 bg-dark-bg-primary/80 rounded-md opacity-0 group-hover:opacity-100 transition-opacity text-danger-400 hover:bg-danger-500/10"
                        title="Delete attachment"
                      >
                        <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                          <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                        </svg>
                      </button>
                    </div>
                  ))}
                </div>
              )}
            </div>

            {/* Comments Section */}
            <div className="bg-dark-bg-secondary border border-dark-border-subtle rounded-lg p-6">
              <h2 className="text-sm font-semibold text-dark-text-primary mb-4">
                Comments {comments.length > 0 && `(${comments.length})`}
              </h2>

              <div className="mb-4">
                {/* Comment toolbar */}
                <div className="flex items-center gap-1 mb-1">
                  <button
                    onClick={() => setImagePickerTarget('comment')}
                    className="inline-flex items-center gap-1 px-2 py-1 text-xs text-dark-text-tertiary hover:text-primary-400 hover:bg-primary-500/10 rounded transition-colors"
                    title="Insert image"
                  >
                    <svg className="w-3.5 h-3.5" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4 16l4.586-4.586a2 2 0 012.828 0L16 16m-2-2l1.586-1.586a2 2 0 012.828 0L20 14m-6-6h.01M6 20h12a2 2 0 002-2V6a2 2 0 00-2-2H6a2 2 0 00-2 2v12a2 2 0 002 2z" />
                    </svg>
                    Insert image
                  </button>
                </div>
                <MentionTextarea
                  ref={commentRef}
                  value={newComment}
                  onChange={setNewComment}
                  projectId={Number(projectId)}
                  rows={3}
                  className="w-full px-3 py-2 border border-dark-border-subtle bg-dark-bg-primary text-dark-text-primary rounded-lg focus:ring-2 focus:ring-primary-500 focus:border-primary-500 outline-none text-sm placeholder-dark-text-tertiary"
                  placeholder="Add a comment... (type @ to mention someone)"
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' && (e.metaKey || e.ctrlKey) && newComment.trim()) {
                      e.preventDefault()
                      handlePostComment()
                    }
                  }}
                />
                <div className="flex justify-between items-center mt-2">
                  <span className="text-xs text-dark-text-tertiary">
                    {navigator.platform.includes('Mac') ? 'Cmd' : 'Ctrl'}+Enter to post
                  </span>
                  <Button
                    onClick={handlePostComment}
                    size="sm"
                    disabled={!newComment.trim() || postingComment}
                  >
                    {postingComment ? 'Posting...' : 'Post Comment'}
                  </Button>
                </div>
              </div>

              <div className="space-y-4">
                {comments.length === 0 ? (
                  <p className="text-sm text-dark-text-tertiary italic">No comments yet</p>
                ) : (
                  comments.map((comment) => (
                    <div key={comment.id} className="border-t border-dark-border-subtle pt-4 first:border-t-0 first:pt-0">
                      <div className="flex items-start gap-3">
                        <div className={`w-8 h-8 rounded-full flex items-center justify-center flex-shrink-0 ${comment.agent_name ? 'bg-violet-500/10' : 'bg-primary-500/10'}`}>
                          <span className={`text-xs font-medium ${comment.agent_name ? 'text-violet-400' : 'text-primary-400'}`}>
                            {comment.agent_name ? 'AI' : (comment.user_name || 'U').charAt(0).toUpperCase()}
                          </span>
                        </div>
                        <div className="flex-1 min-w-0">
                          <div className="flex items-center gap-2 mb-1">
                            <Link
                              to={`/app/users/${comment.user_id}`}
                              className="text-sm font-medium text-dark-text-primary hover:text-primary-400 transition-colors"
                            >
                              {comment.agent_name
                                ? `${comment.agent_name} for ${comment.user_name || `User ${comment.user_id}`}`
                                : comment.user_name || `User ${comment.user_id}`}
                            </Link>
                            {comment.agent_name && (
                              <span className="inline-flex items-center px-1.5 py-0.5 rounded text-[10px] font-medium bg-violet-500/10 text-violet-400 border border-violet-500/20">
                                AI
                              </span>
                            )}
                            <span className="text-xs text-dark-text-tertiary">
                              {new Date(comment.created_at).toLocaleString()}
                            </span>
                          </div>
                          <div className="text-sm text-dark-text-secondary prose prose-sm max-w-none prose-headings:text-dark-text-primary prose-p:text-dark-text-secondary prose-a:text-primary-400 prose-code:text-primary-400 prose-code:bg-primary-500/10 prose-code:px-1 prose-code:py-0.5 prose-code:rounded prose-pre:bg-dark-bg-primary prose-pre:border prose-pre:border-dark-border-subtle prose-strong:text-dark-text-primary prose-li:text-dark-text-secondary prose-img:rounded-lg prose-img:max-h-64 prose-img:border prose-img:border-dark-border-subtle">
                            <ReactMarkdown
                              remarkPlugins={[remarkGfm, remarkEmoji]}
                              components={{
                                a: ({ href, children }) => {
                                  if (href && /figma\.com\/(file|design|proto)\//.test(href)) {
                                    return <FigmaEmbed url={href} size="m" />
                                  }
                                  return <a href={href}>{children}</a>
                                },
                              }}
                            >
                              {preprocessFigmaUrls(comment.comment)}
                            </ReactMarkdown>
                            <ReactionBar reactions={comment.github_reactions} onToggle={(r) => handleToggleReaction(r, comment.id)} />
                          </div>
                        </div>
                      </div>
                    </div>
                  ))
                )}
              </div>
            </div>
          </div>

          {/* Right Column - Sidebar */}
          <div className="w-full md:w-72 flex-shrink-0">
            <div className="bg-dark-bg-secondary border border-dark-border-subtle rounded-lg divide-y divide-dark-border-subtle">
              {/* Swim Lane */}
              <SidebarField label="Swim Lane">
                <SearchSelect
                  variant="inline"
                  value={String(task.swim_lane_id ?? '')}
                  onChange={(v) => saveField('swim_lane_id', v)}
                  options={swimLanes.map(l => ({ value: String(l.id), label: l.name }))}
                />
              </SidebarField>

              {/* Priority */}
              <SidebarField label="Priority">
                <SearchSelect
                  variant="inline"
                  value={task.priority || 'medium'}
                  onChange={(v) => saveField('priority', v)}
                  options={[
                    { value: 'low', label: 'Low' },
