                      </div>
                      <button
                        onClick={() => handleDeleteAttachment(att.id)}
                        className="absolute top-1 right-1 p-1 bg-dark-bg-primary/80 rounded-md opacity-0 group-hover:opacity-100 transition-opacity text-danger-400 hover:bg-danger-500/10"
