          <div className="flex items-center gap-2">
            <span>{error}</span>
            <button onClick={() => setError('')} className="text-danger-400 hover:text-danger-300">
              <svg className="w-4 h-4" fill="none" stroke="currentColor" viewBox="0 0 24 24">
