/**
 * Command Palette (Cmd+K / Ctrl+K)
 * Linear-style command palette for quick navigation and actions
 */

import { useState, useEffect, useMemo, useRef, useCallback, Fragment } from 'react'
import { useNavigate } from 'react-router-dom'
import { Dialog, Transition, Combobox } from '@headlessui/react'
import { useAuth } from '../state/AuthContext'
import { api } from '../lib/api'
import type { SearchTaskResult, GlobalSearchWikiResult } from '../lib/api'

// Detect Mac vs Windows/Linux for keyboard shortcut display
const isMac = typeof navigator !== 'undefined' && /Mac|iPod|iPhone|iPad/.test(navigator.userAgent)
// eslint-disable-next-line react-refresh/only-export-components
export const searchShortcutLabel = isMac ? '⌘K' : 'Ctrl+K'

interface Command {
  id: string
  name: string
  description?: string
  snippet?: string
  icon: string
  action: () => void
  category: 'navigation' | 'actions' | 'tasks' | 'wiki'
  keywords?: string[]
}

export default function CommandPalette() {
  const [isOpen, setIsOpen] = useState(false)
  const [query, setQuery] = useState('')
  const [taskResults, setTaskResults] = useState<SearchTaskResult[]>([])
  const [wikiResults, setWikiResults] = useState<GlobalSearchWikiResult[]>([])
  const [isLoading, setIsLoading] = useState(false)
  const { logout } = useAuth()
  const navigate = useNavigate()
  const abortControllerRef = useRef<AbortController | null>(null)
  const debounceTimerRef = useRef<ReturnType<typeof setTimeout> | null>(null)

  // Keyboard shortcut to open/close palette
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      // Cmd+K (Mac) or Ctrl+K (Windows/Linux)
      if ((e.metaKey || e.ctrlKey) && e.key === 'k') {
        e.preventDefault()
        setIsOpen(open => !open)
      }
      // Escape to close
      if (e.key === 'Escape') {
        setIsOpen(false)
      }
    }

    document.addEventListener('keydown', handleKeyDown)
    return () => document.removeEventListener('keydown', handleKeyDown)
  }, [])

  // Reset state when closed
  useEffect(() => {
    if (!isOpen) {
      setQuery('')
      setTaskResults([])
      setWikiResults([])
      setIsLoading(false)
      if (abortControllerRef.current) {
        abortControllerRef.current.abort()
        abortControllerRef.current = null
      }
      if (debounceTimerRef.current) {
        clearTimeout(debounceTimerRef.current)
        debounceTimerRef.current = null
      }
    }
  }, [isOpen])

  // Debounced search
  const performSearch = useCallback(async (searchQuery: string) => {
    // Cancel any in-flight request
    if (abortControllerRef.current) {
      abortControllerRef.current.abort()

    abortControllerRef.current.abort()
  }

  if (searchQuery.length < 2) {
    setTaskResults([])
    setWikiResults([])
    setIsLoading(false)
    return
  }

  const controller = new AbortController()
  abortControllerRef.current = controller
  setIsLoading(true)

  try {
    const results = await api.globalSearch(searchQuery, undefined, undefined, 10, controller.signal)
    // Only update if this request wasn't aborted
    if (!controller.signal.aborted) {
      setTaskResults(results.tasks)
      setWikiResults(results.wiki)
      setIsLoading(false)
    }
  } catch (err) {
    if (err instanceof DOMException && err.name === 'AbortError') {
      return // Ignore aborted requests
    }
    if (!controller.signal.aborted) {
      setTaskResults([])
      setWikiResults([])
      setIsLoading(false)
    }
  }
}, [])

// Handle query change with debounce
const handleQueryChange = useCallback((value: string) => {
  setQuery(value)

  if (debounceTimerRef.current) {
    clearTimeout(debounceTimerRef.current)
  }

  debounceTimerRef.current = setTimeout(() => {
    performSearch(value)
  }, 150)
}, [performSearch])

// Define available commands
const staticCommands: Command[] = useMemo(() => [
  // Navigation
  {
    id: 'nav-projects',
    name: 'Go to Projects',
    description: 'View all projects',
    icon: '📁',
    category: 'navigation',
    keywords: ['projects', 'list'],
    action: () => {
      navigate('/app')
      setIsOpen(false)
    },
  },
  {
    id: 'nav-cycles',
    name: 'Go to Cycles',
    description: 'View sprint cycles',
    icon: '🔄',
    category: 'navigation',
    keywords: ['sprints', 'cycles', 'iterations'],
    action: () => {
      const pid = localStorage.getItem('taskai_last_project')
      navigate(pid ? `/app/projects/${pid}/sprints` : '/app')
      setIsOpen(false)
    },
  },
  {
    id: 'nav-tags',
    name: 'Go to Tags',
    description: 'Manage labels and tags',
    icon: '🏷️',

