  1→#!/usr/bin/env bash
  2→# TaskAI adapter for unified project runner
  3→#
  4→# Admin: is_admin = 1 in SQLite (users table)
  5→#   User must exist first (sign up via web UI), then grant admin via sqlite3
  6→#   create-admin signs up via local API then sets is_admin = 1
  7→
  8→PROJECT_NAME="taskai"
  9→PROJECT_DOMAIN="taskai.cc"
 10→PROJECT_REPO="anchoo2kewl/taskai"
 11→PROJECT_STACK="Go + React + SQLite"
 12→PROJECT_PORT_BACKEND=8083
 13→PROJECT_PORT_FRONTEND=5174
 14→PROJECT_DB="sqlite"
 15→
 16→_dir="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
 17→_run() { (cd "$_dir" && ./script/server "$@"); }
 18→
 19→# ── Remote config ────────────────────────────────────────────────
 20→_deploy_path() {
 21→    case "$1" in
 22→        staging) echo "/home/ubuntu/taskai-staging" ;;
 23→        uat)     echo "/home/ubuntu/taskai-uat" ;;
 24→        prod)    echo "/home/ubuntu/taskai" ;;
 25→    esac
 26→}
 27→
 28→_api_container() {
 29→    case "$1" in
 30→        staging) echo "taskai-staging-api-1" ;;
 31→        uat)     echo "taskai-uat-api-1" ;;
 32→        prod)    echo "taskai-api-1" ;;
 33→    esac
 34→}
 35→
 36→_api_port() {
 37→    case "$1" in
 38→        staging) echo 8083 ;;
 39→        uat)     echo 38888 ;;
 40→        prod)    echo 8082 ;;
 41→    esac
 42→}
 43→
 44→# ── Local ─────────────────────────────────────────────────────────
 45→local_start()         { _run local dev; }
 46→local_stop()          { kill_port "$PROJECT_PORT_BACKEND"; kill_port "$PROJECT_PORT_FRONTEND"; }
 47→local_dev()           { _run local dev; }
 48→local_restart()       { local_stop; sleep 1; local_start; }
 49→local_status()        { _run local:status; }
 50→local_logs()          { _run local:logs "$@"; }
 51→local_test()          { _run test; }
 52→local_test_backend()  { _run test-api; }
 53→local_test_frontend() { _run test-web; }
 54→local_db_migrate()    { print_warning "$PROJECT_NAME: SQLite — no migrations"; }
 55→local_db_reset()      { _run local:clean; }
 56→local_db_seed()       { print_warning "$PROJECT_NAME: no seed command"; }
 57→local_users()         { _run local users:list; }
 58→local_create_admin()  { _run local admin create "$1"; }
 59→
 60→# ── Docker ────────────────────────────────────────────────────────
 61→docker_start()   { _run local:start; }
 62→docker_stop()    { _run local:stop; }
 63→docker_status()  { _run local:status; }
 64→docker_logs()    { _run local:logs "$@"; }
 65→docker_restart() { docker_stop; docker_start; }
 66→
 67→# ── Remote ────────────────────────────────────────────────────────
 68→remote_status() {
 69→    local env="$1" server; server=$(resolve_server "$env") || return 1
 70→    ssh_cmd "$server" "cd '$(_deploy_path "$env")' && docker compose ps"
 71→}
 72→
 73→remote_logs() {
 74→    local env="$1"; shift; local server; server=$(resolve_server "$env") || return 1
 75→    ssh_cmd "$server" "cd '$(_deploy_path "$env")' && docker compose logs --tail=100 -f ${1:-}"
 76→}
 77→
 78→remote_health() {
 79→    local env="$1" domain="$PROJECT_DOMAIN"
 80→    [[ "$env" == "staging" ]] && domain="staging.$PROJECT_DOMAIN"
 81→    [[ "$env" == "uat" ]]     && domain="uat.$PROJECT_DOMAIN"
 82→    if curl -sf "https://$domain/health" >/dev/null 2>&1; then
 83→        echo -e "  ${GREEN}[healthy]${NC} $PROJECT_NAME  https://$domain"
 84→    else
 85→        echo -e "  ${RED}[down]${NC}    $PROJECT_NAME  https://$domain"
 86→    fi
 87→}
 88→
 89→remote_restart() {
 90→    local env="$1" server; server=$(resolve_server "$env") || return 1
 91→    ssh_cmd "$server" "cd '$(_deploy_path "$env")' && docker compose restart"
 92→}
 93→
 94→remote_users() {
 95→    local env="$1" server container
 96→    server=$(resolve_server "$env") || return 1
 97→    container=$(_api_container "$env")
 98→    ssh_cmd "$server" "docker exec -u root $container sh -c '
 99→        command -v sqlite3 >/dev/null 2>&1 || apk add --no-cache sqlite >/dev/null 2>&1
100→        sqlite3 -header -column /data/taskai.db \"SELECT id, email, is_admin, created_at FROM users ORDER BY id;\"
101→    '"
102→}
103→
104→# create-admin <env> <email> <password>
105→# Signs up via local API (bypasses Cloudflare), then sets is_admin = 1 via sqlite3
106→remote_create_admin() {
107→    local env="$1" email="$2" password="$3"
108→    local server port container
109→
110→    server=$(resolve_server "$env") || return 1
111→    port=$(_api_port "$env")
112→    container=$(_api_container "$env")
113→
114→    if [[ -z "$email" || -z "$password" ]]; then
115→        print_error "Usage: <env> create-admin taskai <email> <password>"
116→        return 1
117→    fi
118→
119→    # Step 1: Sign up via local API on the server (bypasses Cloudflare Access)
120→    print_status "Creating user $email on $env..."
121→    local signup_result
122→    signup_result=$(ssh_cmd "$server" "curl -sS -X POST 'http://127.0.0.1:$port/api/auth/signup' \
123→        -H 'Content-Type: application/json' \
124→        -d '{\"email\":\"$email\",\"password\":\"$password\"}'") || {
125→        print_error "Failed to reach API on $env"
126→        return 1
127→    }
128→
129→    if echo "$signup_result" | grep -q "already"; then
130→        print_warning "User $email already exists — granting admin"
131→    elif echo "$signup_result" | grep -q '"id"'; then
132→        print_success "Created user $email"
133→    else
134→        print_error "Signup failed: $signup_result"
135→        return 1
136→    fi
137→
138→    # Step 2: Grant admin via sqlite3 inside the api container
139→    print_status "Granting admin to $email..."
140→    ssh_cmd "$server" "docker exec -u root $container sh -c '
141→        command -v sqlite3 >/dev/null 2>&1 || apk add --no-cache sqlite >/dev/null 2>&1
142→        sqlite3 /data/taskai.db \"UPDATE users SET is_admin = 1 WHERE email = '\"'\"'$email'\"'\"';\"
143→        sqlite3 -header -column /data/taskai.db \"SELECT id, email, is_admin FROM users WHERE email = '\"'\"'$email'\"'\"';\"
144→    '" || {
145→        print_error "Failed to grant admin"
146→        return 1
147→    }
148→
149→    print_success "$email is now admin on $env"
150→}
151→
152→# copy-db <from_env> <to_env>
153→# Copies SQLite file between environments via local temp file
154→# Uses Docker volume mountpoints on the host — no container stop needed
155→copy_db() {
156→    local from_env="$1" to_env="$2"
157→    local from_server to_server
158→    local tmp_file="/tmp/taskai-${from_env}-$(date +%s).db"
159→
160→    from_server=$(resolve_server "$from_env") || return 1
161→    to_server=$(resolve_server "$to_env") || return 1
162→
163→    # Find the volume mountpoints on each host
164→    local from_vol to_vol
165→    from_vol=$(ssh_cmd "$from_server" "docker volume inspect \$(docker inspect $(_api_container "$from_env") --format '{{range .Mounts}}{{if eq .Destination \"/data\"}}{{.Name}}{{end}}{{end}}') --format '{{.Mountpoint}}'") || {
166→        print_error "Failed to find source DB volume on $from_env"
167→        return 1
168→    }
169→
170→    to_vol=$(ssh_cmd "$to_server" "docker volume inspect \$(docker inspect $(_api_container "$to_env") --format '{{range .Mounts}}{{if eq .Destination \"/data\"}}{{.Name}}{{end}}{{end}}') --format '{{.Mountpoint}}'") || {
171→        print_error "Failed to find destination DB volume on $to_env"
172→        return 1
173→    }
174→
175→    # Step 1: Copy source DB to /tmp on source host, then download
176→    print_status "Downloading DB from $from_env..."
177→    ssh_cmd "$from_server" "sudo cp '$from_vol/taskai.db' /tmp/taskai-copy.db && sudo chmod 644 /tmp/taskai-copy.db" || {
