193→        print_error "Failed to upload DB to $to_env"
194→        return 1
195→    }
196→    ssh_cmd "$to_server" "sudo cp /tmp/taskai-copy.db '$to_vol/taskai.db' && rm -f /tmp/taskai-copy.db" || {
197→        print_error "Failed to write DB on $to_env"
198→        return 1
199→    }
